#include <iostream>

int subtract(int a, int b)
{
    std::cerr << "[subtract] a=" << a << " b=" << b << "\n";
    int result = a - b;
    std::cerr << "[subtract] result=" << result << "\n";
    return result;
}

int main()
{
    int a;
    int b;
    std::cin >> a >> b;
    std::cerr << "[main] a=" << a << " b=" << b << "\n";
    std::cout << subtract(a, b) << "\n";
    return 0;
}

