solution_code:
#include <iostream>

int scaled_sum(int a, int b, int scale)
{
    return (a + b) * scale;
}

int main()
{
    int a;
    int b;
    int scale;
    std::cin >> a >> b >> scale;
    std::cerr << "[main] a=" << a << " b=" << b << " scale=" << scale << "\n";
    int result = scaled_sum(a, b, scale);
    std::cerr << "[main] result=" << result << "\n";
    std::cout << "Scaled: " << result << "\n";
    return 0;
}
